#include <stdio.h>
#include <stdlib.h>

const int mod = 1000000007;

void merge(int a[], int size_a, int b[], int size_b, int c[]) {
    int idx1 = 0, idx2 = 0, idx = 0;
    while (idx1 < size_a && idx2 < size_b) {
        if (a[idx1] < b[idx2]) {
            c[idx++] = a[idx1++];
        } else {
            c[idx++] = b[idx2++];
        }
    }
    while (idx1 < size_a) c[idx++] = a[idx1++];
    while (idx2 < size_b) c[idx++] = b[idx2++];
}

// Counts pairs (i, j) such that a[i] > b[j]
// Both a[] and b[] are sorted ascending
int countInversions(int a[], int size_a, int b[], int size_b) {
    int ptr = 0;
    int ans = 0;
    for (int i = 0; i < size_a; i++) {
        // Move ptr right while b[ptr] < a[i]
        while (ptr < size_b && b[ptr] < a[i]) {
            ptr++;
        }
        // Elements 0..ptr-1 are all < a[i], count = ptr
        ans = (ans + ptr) % mod;
    }
    return ans;
}

int sortAndCount(int a[], int size_a) {
    if (size_a == 1) return 0;

    int mid = size_a / 2;
    int sz1 = mid;
    int sz2 = size_a - sz1;

    // Heap allocation to avoid stack overflow on large N
    int *a1 = (int *)malloc(sz1 * sizeof(int));
    int *a2 = (int *)malloc(sz2 * sizeof(int));

    for (int i = 0; i < sz1; i++) a1[i] = a[i];
    for (int i = 0; i < sz2; i++) a2[i] = a[mid + i];

    int left  = sortAndCount(a1, sz1);
    int right = sortAndCount(a2, sz2);
    int num   = countInversions(a1, sz1, a2, sz2);

    merge(a1, sz1, a2, sz2, a);

    free(a1);
    free(a2);

    return (((left + right) % mod) + num) % mod;
}

int main() {
    int t;
    scanf("%d", &t);

    while (t--) {
        int n;
        scanf("%d", &n);

        int *a = (int *)malloc(n * sizeof(int));
        for (int i = 0; i < n; i++) scanf("%d", &a[i]);

        printf("%d\n", sortAndCount(a, n));

        free(a);
    }
    return 0;
}

