    }
}


// Calculates the number of pairs of indexes (i, j) 
// such that ai > bj
int Inversion(int a[], int size_a, int b[], int size_b) {
    int ptr = size_b - 1;
    int ans = 0;
    for(int i = 0; i < size_a; i++) {   
        while(ptr >= 0 && b[ptr] < a[i]) { 
            ptr--;
        }
        ans = (ans + (size_b - 1 - ptr)) % mod;
    }
    return ans;
}

int Sort(int a[], int size_a) {
    if(size_a == 1) {
        return 0;
    }

    int mid = size_a / 2;

    int sz1 = mid;
    int sz2 = size_a - sz1;

    int a1[sz1];
    int a2[sz2];

    for(int i = 0; i < mid; i++) {
        a1[i] = a[i];
    }

    for(int i = mid; i < size_a; i++) {
        a2[i - mid] = a[i];
    }

    // Number of inversions in the left and right subarray
    int left = Sort(a1, sz1); 
    int right = Sort(a2, sz2);

    // Number of inversions when both halves are put together 
    int num = Inversion(a1, sz1, a2, sz2);

    Merge(a1, sz1, a2, sz2, a);

    return (((left + right) % mod) + num) % mod;
}

